var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"드디어 누나랑 영원히 함께할 마음이 생겼니?","JPN":"やっとお姉ちゃんと永遠をともにする気になった？","ENG":"Did you finally decide to spend the rest of your life with me?","TWN":"你終於想定下來啦？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후훗♬ 마침내 누나의 진심이 전해졌구나. 알아 줘서 정말 기뻐.","JPN":"うふふっ♬ついにお姉ちゃんの思いが届いたのね。わかってもらえてとっても嬉しいわ。","ENG":"Uhu huu♬ My feelings finally went through. I’m so glad you came to realize.","TWN":"呵呵呵♬ 你終於感受到姊姊的真心啦？我好開心～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"실은 말이지, 누나는 이 몸이 그렇게 마음에 들지 않았어. 처음 알았지?","JPN":"実はね、お姉ちゃんはこの身体があまり好きじゃなかったの。知らなかったでしょ？","ENG":"The truth is, I’m not that fond of this body. First time hearing this, right?","TWN":"不過你知道嗎？其實我不是很喜歡現在的身體，這你是第一次聽說吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"누나는 원래 누나처럼 나긋나긋한 몸을 좋아하거든.","JPN":"お姉ちゃんはお姉ちゃんの本来の姿のような、しなやかな身体が好きなのよね。","ENG":"Truth is, I actually prefer a body that’s as soft as the original me.","TWN":"我喜歡我原本軟綿綿的身體～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 이유는 간단해. 인간을 꼬옥 안아 주려면 만질 때 무척 포근하고 말랑말랑해야 하니까.","JPN":"ふふっ、理由は簡単よ。人間をギュッと抱きしめてあげるためには、触れたときにとってもふわふわで柔らかくなければいけないもの。","ENG":"Fuu fuu, the reason is simple. To give a human a nice tender hug, you need a body that’s cozy to the touch.","TWN":"呵呵，原因很簡單，這樣抱起來才會軟軟的很舒服呀～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그런데 이 몸은 예전 주인이 어떻게 썼는지 딱딱한 데다가 상처투성이라서…….","JPN":"でも、この身体は前の持ち主の使い方が荒かったのか堅くて傷もたくさんで……","ENG":"I don’t know what the previous owner of this body was doing, but this body is stiff and covered in wounds...","TWN":"不過這個身體的主人不知道怎麼搞的，不只身體很僵硬，而且還有很多傷疤……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"……응? 그 이야기는 듣고 싶지 않다고?","JPN":"……え？　その話は聞きたくない？","ENG":"...Hmm? You don’t want to hear about that?","TWN":"……嗯？你想聽的不是這個喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"미안, 누나 잘못이야. 사장님은 그깟 인간보다 누나에게 관심이 더 많을 텐데.","JPN":"ごめんね、お姉ちゃんが悪かったわ。社長はそんな人間なんかよりお姉ちゃんのことを知りたいよね。","ENG":"Sorry, my bad. I’m sure you’re more interested in me more than a mere human like her.","TWN":"不好意思喔，是姊姊不好，畢竟老闆是對我有興趣，不是對那個人有興趣對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"하고 싶었던 말은, 사장님이 이런 꼴이 된 누나에게 응석을 부려 줘서 정말정말 행복하고 고마웠다는 거야.","JPN":"お姉ちゃんが言いたかったのは、社長がこんな姿になったお姉ちゃんに甘えてくれて本当に本当に幸せで嬉しかったってこと。","ENG":"What I’m trying to say is, I’m just so so happy and thankful to you for coddling someone in such a bad state like me.","TWN":"姊姊想說的話是，謝謝老闆願意接受變成這樣的我，我真的感到非常幸福。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그러니까 앞으로 필요하면 언제든, 누나를 부를 것. 알겠지?","JPN":"だから、これから必要な時はいつだってお姉ちゃんを呼んでね。絶対よ？","ENG":"So if you ever need anything, just give me a call. Alright?","TWN":"所以以後只要有需要，隨時找姊姊！知道嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"사장님을 위해서라면…… 누나는 세상 전부를 적으로 돌리더라도 상관없으니까.","JPN":"社長のためなら……お姉ちゃんは世界中を敵に回したってかまわないんだから。","ENG":"If for you... I wouldn’t mind if I had to turn the whole world against me.","TWN":"只要是跟老闆有關的事……就算要我與全世界為敵，我也願意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};